={
  "query": "SELECT campaign.id, campaign.name, campaign.status, metrics.impressions, metrics.clicks, metrics.cost_micros, metrics.conversions, metrics.conversions_value, metrics.ctr, metrics.average_cpc FROM campaign WHERE segments.date BETWEEN '{{ $json.date_start }}' AND '{{ $json.date_end }}' AND campaign.status != 'REMOVED' ORDER BY metrics.cost_micros DESC"
}

parameters.jsCode:
const items = $input.all();

const config = items.find(i => i.json && i.json.google_ads_customer_id)?.json || items[0]?.json;
const date_start = config.date_start;
const date_end = config.date_end;
const report_type = config.report_type;

let googleAds = { campaigns: [], totals: {} };
let metaAds = { campaigns: [], totals: {} };
let ga4 = { rows: [], totals: {} };
let fetchStatus = { googleAds: 'ok', metaAds: 'ok', ga4: 'ok' };

for (const item of items) {
  const j = item.json || {};
  if (j.results && Array.isArray(j.results) && j.results[0]?.campaign) {
    googleAds.campaigns = j.results.flatMap(r => (r.campaign || []).map(c => {
      const m = (r.metrics && r.metrics[0]) || {};
      return {
        id: c.id, name: c.name, status: c.status,
        impressions: Number(m.impressions || 0),
        clicks: Number(m.clicks || 0),
        cost: Number(m.costMicros || m.cost_micros || 0) / 1e6,
        conversions: Number(m.conversions || 0),
        conversion_value: Number(m.conversionsValue || m.conversions_value || 0),
        ctr: Number(m.ctr || 0),
        avg_cpc: Number(m.averageCpc || m.average_cpc || 0) / 1e6
      };
    }));
  } else if (j.data && Array.isArray(j.data)) {
    metaAds.campaigns = j.data.map(d => {
      const actions = Array.isArray(d.actions) ? d.actions : [];
      const purchases = actions.find(a => a.action_type === 'purchase') || {};
      const roas = Array.isArray(d.purchase_roas) ? d.purchase_roas : [];
      return {
        id: d.campaign_id, name: d.campaign_name,
        impressions: Number(d.impressions || 0),
        clicks: Number(d.clicks || 0),
        spend: Number(d.spend || 0),
        ctr: Number(d.ctr || 0),
        cpc: Number(d.cpc || 0),
        cpm: Number(d.cpm || 0),
        reach: Number(d.reach || 0),
        frequency: Number(d.frequency || 0),
        conversions: Number(purchases.value || 0),
        purchase_roas: roas[0]?.value ? Number(roas[0].value) : 0,
        date_start: d.date_start, date_stop: d.date_stop
      };
    });
  } else if (j.rows && Array.isArray(j.rows)) {
    ga4.rows = j.rows.map(r => ({
      channel: r.dimensionValues?.[0]?.value || 'unknown',
      sessions: Number(r.metricValues?.[0]?.value || 0),
      users: Number(r.metricValues?.[1]?.value || 0),
      newUsers: Number(r.metricValues?.[2]?.value || 0),
      pageviews: Number(r.metricValues?.[3]?.value || 0),
      engagedSessions: Number(r.metricValues?.[4]?.value || 0),
      conversions: Number(r.metricValues?.[5]?.value || 0),
      revenue: Number(r.metricValues?.[6]?.value || 0),
      bounceRate: Number(r.metricValues?.[7]?.value || 0),
      avgSessionDuration: Number(r.metricValues?.[8]?.value || 0)
    }));
  }
}

function sum(arr, key) { return arr.reduce((s, x) => s + (x[key] || 0), 0); }

if (googleAds.campaigns.length === 0) fetchStatus.googleAds = 'empty';
if (metaAds.campaigns.length === 0) fetchStatus.metaAds = 'empty';
if (ga4.rows.length === 0) fetchStatus.ga4 = 'empty';

googleAds.totals = {
  impressions: sum(googleAds.campaigns, 'impressions'),
  clicks: sum(googleAds.campaigns, 'clicks'),
  cost: sum(googleAds.campaigns, 'cost'),
  conversions: sum(googleAds.campaigns, 'conversions'),
  conversion_value: sum(googleAds.campaigns, 'conversion_value'),
  ctr: googleAds.campaigns.length ? (sum(googleAds.campaigns, 'clicks') / Math.max(sum(googleAds.campaigns, 'impressions'), 1)) * 100 : 0,
  cpa: googleAds.campaigns.length ? sum(googleAds.campaigns, 'cost') / Math.max(sum(googleAds.campaigns, 'conversions'), 1) : 0,
  roas: googleAds.campaigns.length ? sum(googleAds.campaigns, 'conversion_value') / Math.max(sum(googleAds.campaigns, 'cost'), 1) : 0
};

metaAds.totals = {
  impressions: sum(metaAds.campaigns, 'impressions'),
  clicks: sum(metaAds.campaigns, 'clicks'),
  spend: sum(metaAds.campaigns, 'spend'),
  conversions: sum(metaAds.campaigns, 'conversions'),
  reach: sum(metaAds.campaigns, 'reach'),
  ctr: metaAds.campaigns.length ? (sum(metaAds.campaigns, 'clicks') / Math.max(sum(metaAds.campaigns, 'impressions'), 1)) * 100 : 0,
  cpc: metaAds.campaigns.length ? sum(metaAds.campaigns, 'spend') / Math.max(sum(metaAds.campaigns, 'clicks'), 1) : 0,
  cpa: metaAds.campaigns.length ? sum(metaAds.campaigns, 'spend') / Math.max(sum(metaAds.campaigns, 'conversions'), 1) : 0,
  roas: metaAds.campaigns.length && sum(metaAds.campaigns, 'spend') > 0
    ? sum(metaAds.campaigns.map(c => c.purchase_roas * c.spend)) / sum(metaAds.campaigns, 'spend')
    : 0
};

ga4.totals = {
  sessions: sum(ga4.rows, 'sessions'),
  users: sum(ga4.rows, 'users'),
  newUsers: sum(ga4.rows, 'newUsers'),
  pageviews: sum(ga4.rows, 'pageviews'),
  engagedSessions: sum(ga4.rows, 'engagedSessions'),
  conversions: sum(ga4.rows, 'conversions'),
  revenue: sum(ga4.rows, 'revenue'),
  bounceRate: ga4.rows.length ? (sum(ga4.rows, 'bounceRate') / ga4.rows.length) : 0,
  avgSessionDuration: ga4.rows.length ? (sum(ga4.rows, 'avgSessionDuration') / ga4.rows.length) : 0
};

const crossChannel = {
  total_ad_spend: googleAds.totals.cost + metaAds.totals.spend,
  total_conversions: googleAds.totals.conversions + metaAds.totals.conversions + ga4.totals.conversions,
  total_revenue: googleAds.totals.conversion_value + (metaAds.totals.spend * (metaAds.totals.roas || 0)) + ga4.totals.revenue,
  overall_roas: 0,
  overall_cpa: 0,
  overall_ctr: ((googleAds.totals.clicks + metaAds.totals.clicks) / Math.max(googleAds.totals.impressions + metaAds.totals.impressions, 1)) * 100
};
crossChannel.overall_roas = crossChannel.total_ad_spend > 0 ? crossChannel.total_revenue / crossChannel.total_ad_spend : 0;
crossChannel.overall_cpa = crossChannel.total_conversions > 0 ? crossChannel.total_ad_spend / crossChannel.total_conversions : 0;

return {
  json: {
    ...config,
    googleAds,
    metaAds,
    ga4,
    crossChannel,
    fetchStatus,
    report_period: { start: date_start, end: date_end, type: report_type },
    generated_at: new Date().toISOString()
  }
};

const d = $json;

const spendByChannel = [
  { channel: 'Google Ads', spend: d.googleAds.totals.cost, conversions: d.googleAds.totals.conversions, revenue: d.googleAds.totals.conversion_value },
  { channel: 'Meta Ads', spend: d.metaAds.totals.spend, conversions: d.metaAds.totals.conversions, revenue: d.metaAds.totals.spend * (d.metaAds.totals.roas || 0) },
  { channel: 'GA4 (Organic + Other)', spend: 0, conversions: d.ga4.totals.conversions, revenue: d.ga4.totals.revenue }
];

const ga4ChannelMix = d.ga4.rows.map(r => ({ channel: r.channel, sessions: r.sessions, conversions: r.conversions }));

const topGoogle = [...d.googleAds.campaigns].sort((a,b)=>b.conversion_value-a.conversion_value).slice(0,5);
const topMeta = [...d.metaAds.campaigns].sort((a,b)=>(b.purchase_roas*b.spend)-(a.purchase_roas*a.spend)).slice(0,5);

const fmtUSD = (v) => `$${(Number(v)||0).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}`;
const fmtNum = (v) => Number(v||0).toLocaleString('en-US');
const fmtPct = (v) => `${(Number(v)||0).toFixed(2)}%`;

return { json: {
  ...d,
  chartData: { spendByChannel, ga4ChannelMix, topGoogle, topMeta },
  formatted: {
    googleAds: {
      spend: fmtUSD(d.googleAds.totals.cost),
      revenue: fmtUSD(d.googleAds.totals.conversion_value),
      conversions: fmtNum(d.googleAds.totals.conversions),
      ctr: fmtPct(d.googleAds.totals.ctr),
      cpa: fmtUSD(d.googleAds.totals.cpa),
      roas: `${(d.googleAds.totals.roas||0).toFixed(2)}x`
    },
    metaAds: {
      spend: fmtUSD(d.metaAds.totals.spend),
      revenue: fmtUSD(d.metaAds.totals.spend * (d.metaAds.totals.roas||0)),
      conversions: fmtNum(d.metaAds.totals.conversions),
      ctr: fmtPct(d.metaAds.totals.ctr),
      cpa: fmtUSD(d.metaAds.totals.cpa),
      roas: `${(d.metaAds.totals.roas||0).toFixed(2)}x`
    },
    ga4: {
      sessions: fmtNum(d.ga4.totals.sessions),
      users: fmtNum(d.ga4.totals.users),
      newUsers: fmtNum(d.ga4.totals.newUsers),
      pageviews: fmtNum(d.ga4.totals.pageviews),
      conversions: fmtNum(d.ga4.totals.conversions),
      revenue: fmtUSD(d.ga4.totals.revenue),
      bounceRate: fmtPct(d.ga4.totals.bounceRate),
      avgSessionDuration: `${Math.round((d.ga4.totals.avgSessionDuration||0))}s`
    },
    crossChannel: {
      totalSpend: fmtUSD(d.crossChannel.total_ad_spend),
      totalRevenue: fmtUSD(d.crossChannel.total_revenue),
      totalConversions: fmtNum(d.crossChannel.total_conversions),
      overallRoas: `${(d.crossChannel.overall_roas||0).toFixed(2)}x`,
      overallCpa: fmtUSD(d.crossChannel.overall_cpa),
      overallCtr: fmtPct(d.crossChannel.overall_ctr)
    }
  }
} };

parameters.text:
=You are a senior marketing analyst preparing an executive client report.

Analyze the campaign performance data below and produce a CLIENT-FRIENDLY executive summary with these sections (in this exact order):

1. **Headline Summary** (2-3 sentences): top-line performance verdict for the {{ $json.report_period.start }} → {{ $json.report_period.end }} period.
2. **Key Wins** (3-5 bullet points): what worked well — be specific with numbers.
3. **Key Issues** (2-4 bullet points): underperforming areas — be specific and constructive.
4. **Cross-Channel Insights**: how Google Ads, Meta Ads, and GA4 traffic interact (e.g., is paid traffic driving engaged sessions?).
5. **Recommended Actions** (3-5 bullet points): prioritized, concrete next steps for the client.
6. **Forecast / Outlook**: 1-2 sentences on projected trend if current pace continues.

Keep the tone professional, clear, and action-oriented. Avoid jargon. Use exact numbers from the data. Highlight any anomalies.

---
PERFORMANCE DATA:

**Cross-Channel Totals:**
- Total Ad Spend: ${{ $json.crossChannel.total_ad_spend.toFixed(2) }}
- Total Revenue: ${{ $json.crossChannel.total_revenue.toFixed(2) }}
- Total Conversions: {{ $json.crossChannel.total_conversions }}
- Overall ROAS: {{ $json.crossChannel.overall_roas.toFixed(2) }}x
- Overall CPA: ${{ $json.crossChannel.overall_cpa.toFixed(2) }}
- Overall CTR: {{ $json.crossChannel.overall_ctr.toFixed(2) }}%

**Google Ads:**
- Spend: ${{ $json.googleAds.totals.cost.toFixed(2) }}
- Revenue: ${{ $json.googleAds.totals.conversion_value.toFixed(2) }}
- Conversions: {{ $json.googleAds.totals.conversions }}
- CTR: {{ $json.googleAds.totals.ctr.toFixed(2) }}%
- CPA: ${{ $json.googleAds.totals.cpa.toFixed(2) }}
- ROAS: {{ $json.googleAds.totals.roas.toFixed(2) }}x
- Top campaigns:
{{ $json.googleAds.campaigns.slice(0,5).map(c => `  • ${c.name}: spend $${c.cost.toFixed(2)}, conv ${c.conversions}, ROAS ${c.conversion_value > 0 && c.cost > 0 ? (c.conversion_value/c.cost).toFixed(2) : 0}x`).join('\n') }}

**Meta Ads:**
- Spend: ${{ $json.metaAds.totals.spend.toFixed(2) }}
- Conversions: {{ $json.metaAds.totals.conversions }}
- CTR: {{ $json.metaAds.totals.ctr.toFixed(2) }}%
- CPA: ${{ $json.metaAds.totals.cpa.toFixed(2) }}
- ROAS: {{ $json.metaAds.totals.roas.toFixed(2) }}x
- Top campaigns:
{{ $json.metaAds.campaigns.slice(0,5).map(c => `  • ${c.name}: spend $${c.spend.toFixed(2)}, conv ${c.conversions}, ROAS ${c.purchase_roas.toFixed(2)}x`).join('\n') }}

**GA4 (website analytics):**
- Sessions: {{ $json.ga4.totals.sessions }}
- Users: {{ $json.ga4.totals.users }}
- New Users: {{ $json.ga4.totals.newUsers }}
- Engaged Sessions: {{ $json.ga4.totals.engagedSessions }}
- Conversions: {{ $json.ga4.totals.conversions }}
- Revenue: ${{ $json.ga4.totals.revenue.toFixed(2) }}
- Bounce Rate: {{ $json.ga4.totals.bounceRate.toFixed(2) }}%
- Avg Session Duration: {{ $json.ga4.totals.avgSessionDuration.toFixed(0) }}s
- Channels:
{{ $json.ga4.rows.map(r => `  • ${r.channel}: ${r.sessions} sessions, ${r.conversions} conversions, $${r.revenue.toFixed(2)} revenue`).join('\n') }}

---
Fetch status: Google Ads={{ $json.fetchStatus.googleAds }}, Meta Ads={{ $json.fetchStatus.metaAds }}, GA4={{ $json.fetchStatus.ga4 }}.
If any source was empty/failed, acknowledge briefly and base insights on available data only.

parameters.jsCode:
const items = $input.all();
const errors = items.filter(i => i.json.error || i.json.message).map(i => ({
  node: i.json.node || 'unknown',
  error: (i.json.error?.message || i.json.message || 'unknown error').substring(0, 500)
}));

return {
  json: {
    alert_title: '🚨 Marketing Report Workflow ERROR',
    client_id: items[0]?.json?.client_id || 'unknown',
    period: items[0]?.json?.report_period || { start: 'unknown', end: 'unknown' },
    timestamp: new Date().toISOString(),
    execution_id: $execution.id,
    error_count: errors.length,
    errors: errors,
    summary: errors.map(e => `• ${e.node}: ${e.error}`).join('\n')
  }
};
